class Solution:
    def separateSquares(self, squares):
        pts = set()
        for _, y, l in squares:
            pts.add(y)
            pts.add(y + l)
        pts = sorted(pts)
        total = sum(l * l for _, _, l in squares)
        target = total / 2

        def below(Y):
            return sum(max(0.0, min(Y, y + l) - y) * l for _, y, l in squares)

        for i in range(len(pts) - 1):
            Y0, Y1 = pts[i], pts[i + 1]
            C0 = below(Y0)
            C1 = below(Y1)
            if C0 <= target <= C1:
                if C1 == C0:
                    return Y0
                frac = (target - C0) / (C1 - C0)
                return Y0 + frac * (Y1 - Y0)
        return pts[-1]

