class Solution:
    def separateSquares(self, squares):
        lo = min(s[1] for s in squares)
        hi = max(s[1] + s[2] for s in squares)
        total = sum(s[2] * s[2] for s in squares)
        target = total / 2
        for _ in range(100):
            mid = (lo + hi) / 2
            below = sum(max(0.0, min(mid, s[1] + s[2]) - s[1]) * s[2] for s in squares)
            if below < target:
                lo = mid
            else:
                hi = mid
        return (lo + hi) / 2

