var separateSquares = function(squares) {
    let lo = Math.min(...squares.map(s => s[1]));
    let hi = Math.max(...squares.map(s => s[1] + s[2]));
    const total = squares.reduce((acc, s) => acc + s[2] * s[2], 0);
    const target = total / 2;
    for (let iter = 0; iter < 100; iter++) {
        const mid = (lo + hi) / 2;
        let below = 0;
        for (const [, y, l] of squares) {
            below += Math.max(0, Math.min(mid, y + l) - y) * l;
        }
        if (below < target) lo = mid; else hi = mid;
    }
    return (lo + hi) / 2;
};
